'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import { useAuth } from '@/contexts/auth-context';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Skeleton } from '@/components/ui/skeleton';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  ClockCounterClockwiseIcon,
  MagnifyingGlassIcon,
  FunnelIcon,
  EyeIcon,
  WarningCircleIcon,
  ShieldCheckIcon,
} from '@phosphor-icons/react';
import type { AuditLogEntry, AuditAction } from '@/lib/types';
import { format, formatDistanceToNow } from 'date-fns';

const ENTITY_TYPES = [
  { value: 'all', label: 'All Types' },
  { value: 'application', label: 'Applications' },
  { value: 'document', label: 'Documents' },
  { value: 'user', label: 'Users' },
];

const ACTION_LABELS: Record<AuditAction, string> = {
  application_created: 'Application Created',
  application_submitted: 'Application Submitted',
  application_assigned: 'Application Assigned',
  review_started: 'Review Started',
  additional_info_requested: 'Additional Info Requested',
  additional_info_submitted: 'Additional Info Submitted',
  review_completed: 'Review Completed',
  application_approved: 'Application Approved',
  application_rejected: 'Application Rejected',
  document_uploaded: 'Document Uploaded',
  document_version_added: 'Document Version Added',
  user_created: 'User Created',
  user_updated: 'User Updated',
  user_login: 'User Login',
  user_logout: 'User Logout',
};

export default function AuditLogPage() {
  const { permissions } = useAuth();
  const [auditLog, setAuditLog] = useState<AuditLogEntry[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [entityTypeFilter, setEntityTypeFilter] = useState('all');

  // Detail view dialog
  const [selectedEntry, setSelectedEntry] = useState<AuditLogEntry | null>(null);
  const [showDetailDialog, setShowDetailDialog] = useState(false);

  useEffect(() => {
    fetchAuditLog();
  }, [entityTypeFilter]);

  async function fetchAuditLog() {
    try {
      const params = new URLSearchParams();
      if (entityTypeFilter && entityTypeFilter !== 'all') {
        params.append('entityType', entityTypeFilter);
      }

      const response = await fetch(`/api/audit-log?${params.toString()}`);
      if (response.ok) {
        const data = await response.json();
        setAuditLog(data.auditLog || []);
      }
    } catch (error) {
      console.error('Failed to fetch audit log:', error);
    } finally {
      setIsLoading(false);
    }
  }

  function openDetailDialog(entry: AuditLogEntry) {
    setSelectedEntry(entry);
    setShowDetailDialog(true);
  }

  const getActionBadge = (action: AuditAction) => {
    let variant: 'default' | 'secondary' | 'destructive' | 'outline' = 'secondary';
    let className = '';

    if (action.includes('approved')) {
      variant = 'default';
      className = 'bg-green-500';
    } else if (action.includes('rejected')) {
      variant = 'destructive';
    } else if (action.includes('login') || action.includes('logout')) {
      variant = 'outline';
    } else if (action.includes('created') || action.includes('submitted')) {
      variant = 'default';
      className = 'bg-blue-500';
    }

    return (
      <Badge variant={variant} className={className}>
        {ACTION_LABELS[action] || action.replace(/_/g, ' ')}
      </Badge>
    );
  };

  const filteredLog = auditLog.filter((entry) => {
    if (!searchQuery) return true;
    const query = searchQuery.toLowerCase();
    return (
      entry.userName.toLowerCase().includes(query) ||
      entry.userEmail.toLowerCase().includes(query) ||
      entry.action.toLowerCase().includes(query) ||
      entry.entityId.toLowerCase().includes(query)
    );
  });

  if (!permissions?.canViewAuditLog) {
    return (
      <div className="flex flex-col items-center justify-center py-12">
        <WarningCircleIcon className="h-12 w-12 text-destructive mb-4" />
        <h1 className="text-xl font-bold">Access Denied</h1>
        <p className="text-muted-foreground mt-2">
          You do not have permission to view the audit log.
        </p>
        <Link href="/dashboard" className="mt-4">
          <Button>Return to Dashboard</Button>
        </Link>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-2xl font-bold tracking-tight">Audit Log</h1>
          <p className="text-muted-foreground">
            Complete record of all system actions (immutable)
          </p>
        </div>
        <div className="flex items-center gap-2 text-sm text-muted-foreground">
          <ShieldCheckIcon size={20} />
          <span>Tamper-proof audit trail</span>
        </div>
      </div>

      {/* Filters */}
      <Card>
        <CardContent className="pt-6">
          <div className="flex flex-col gap-4 sm:flex-row sm:items-center">
            <div className="relative flex-1">
              <MagnifyingGlassIcon className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
              <Input
                placeholder="Search by user, action, or entity ID..."
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-9"
              />
            </div>
            <div className="flex items-center gap-2">
              <FunnelIcon className="h-4 w-4 text-muted-foreground" />
              <Select value={entityTypeFilter} onValueChange={setEntityTypeFilter}>
                <SelectTrigger className="w-[180px]">
                  <SelectValue placeholder="Filter by type" />
                </SelectTrigger>
                <SelectContent>
                  {ENTITY_TYPES.map((option) => (
                    <SelectItem key={option.value} value={option.value}>
                      {option.label}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Audit Log Table */}
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <ClockCounterClockwiseIcon size={20} />
            {filteredLog.length} Entries
          </CardTitle>
          <CardDescription>
            Click on an entry to view full details including state changes
          </CardDescription>
        </CardHeader>
        <CardContent>
          {isLoading ? (
            <div className="space-y-4">
              {[...Array(10)].map((_, i) => (
                <div key={i} className="flex items-center gap-4">
                  <div className="space-y-2 flex-1">
                    <Skeleton className="h-4 w-64" />
                    <Skeleton className="h-3 w-40" />
                  </div>
                  <Skeleton className="h-6 w-32" />
                </div>
              ))}
            </div>
          ) : filteredLog.length === 0 ? (
            <div className="text-center py-12 text-muted-foreground">
              <ClockCounterClockwiseIcon className="h-12 w-12 mx-auto mb-4 opacity-50" />
              <p>No audit log entries found</p>
            </div>
          ) : (
            <div className="overflow-x-auto">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Timestamp</TableHead>
                    <TableHead>Action</TableHead>
                    <TableHead>User</TableHead>
                    <TableHead>Entity</TableHead>
                    <TableHead className="text-right">Details</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filteredLog.map((entry) => (
                    <TableRow key={entry.id}>
                      <TableCell className="whitespace-nowrap">
                        <div>
                          <div className="font-medium">
                            {format(new Date(entry.timestamp), 'PP')}
                          </div>
                          <div className="text-xs text-muted-foreground">
                            {format(new Date(entry.timestamp), 'pp')}
                          </div>
                        </div>
                      </TableCell>
                      <TableCell>{getActionBadge(entry.action)}</TableCell>
                      <TableCell>
                        <div>
                          <div className="font-medium">{entry.userName}</div>
                          <div className="text-xs text-muted-foreground capitalize">
                            {entry.userRole}
                          </div>
                        </div>
                      </TableCell>
                      <TableCell>
                        <div>
                          <div className="font-medium capitalize">{entry.entityType}</div>
                          <div className="text-xs text-muted-foreground font-mono">
                            {entry.entityId.slice(0, 8)}...
                          </div>
                        </div>
                      </TableCell>
                      <TableCell className="text-right">
                        <Button
                          variant="ghost"
                          size="sm"
                          onClick={() => openDetailDialog(entry)}
                          className="gap-2"
                        >
                          <EyeIcon size={16} />
                          View
                        </Button>
                      </TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Entry Detail Dialog */}
      <Dialog open={showDetailDialog} onOpenChange={setShowDetailDialog}>
        <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Audit Log Entry Details</DialogTitle>
            <DialogDescription>
              Complete record of this action
            </DialogDescription>
          </DialogHeader>
          {selectedEntry && (
            <div className="space-y-6">
              <div className="grid gap-4 sm:grid-cols-2">
                <div>
                  <h4 className="text-sm font-medium text-muted-foreground mb-1">Timestamp</h4>
                  <p className="font-medium">
                    {format(new Date(selectedEntry.timestamp), 'PPpp')}
                  </p>
                  <p className="text-sm text-muted-foreground">
                    {formatDistanceToNow(new Date(selectedEntry.timestamp), { addSuffix: true })}
                  </p>
                </div>
                <div>
                  <h4 className="text-sm font-medium text-muted-foreground mb-1">Action</h4>
                  {getActionBadge(selectedEntry.action)}
                </div>
              </div>

              <div className="grid gap-4 sm:grid-cols-2">
                <div>
                  <h4 className="text-sm font-medium text-muted-foreground mb-1">User</h4>
                  <p className="font-medium">{selectedEntry.userName}</p>
                  <p className="text-sm text-muted-foreground">{selectedEntry.userEmail}</p>
                  <Badge variant="outline" className="mt-1 capitalize">
                    {selectedEntry.userRole}
                  </Badge>
                </div>
                <div>
                  <h4 className="text-sm font-medium text-muted-foreground mb-1">Entity</h4>
                  <p className="font-medium capitalize">{selectedEntry.entityType}</p>
                  <p className="text-sm font-mono text-muted-foreground break-all">
                    {selectedEntry.entityId}
                  </p>
                </div>
              </div>

              <div>
                <h4 className="text-sm font-medium text-muted-foreground mb-1">Entry ID</h4>
                <p className="text-sm font-mono break-all">{selectedEntry.id}</p>
              </div>

              {selectedEntry.stateBefore && (
                <div>
                  <h4 className="text-sm font-medium text-muted-foreground mb-1">State Before</h4>
                  <pre className="bg-muted p-3 rounded-lg text-xs overflow-x-auto">
                    {JSON.stringify(JSON.parse(selectedEntry.stateBefore), null, 2)}
                  </pre>
                </div>
              )}

              {selectedEntry.stateAfter && (
                <div>
                  <h4 className="text-sm font-medium text-muted-foreground mb-1">State After</h4>
                  <pre className="bg-muted p-3 rounded-lg text-xs overflow-x-auto">
                    {JSON.stringify(JSON.parse(selectedEntry.stateAfter), null, 2)}
                  </pre>
                </div>
              )}

              {selectedEntry.metadata && (
                <div>
                  <h4 className="text-sm font-medium text-muted-foreground mb-1">Metadata</h4>
                  <pre className="bg-muted p-3 rounded-lg text-xs overflow-x-auto">
                    {JSON.stringify(JSON.parse(selectedEntry.metadata), null, 2)}
                  </pre>
                </div>
              )}

              <div className="border-t pt-4 text-xs text-muted-foreground">
                <p>This audit log entry is immutable and cannot be modified or deleted.</p>
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}
